import React, {useState, useEffect} from "react";
import axios from "axios";

const API = "http://127.0.0.1:5000";

function App(){
  const [students,setStudents] = useState([]);
  const [form,setForm] = useState({name:"",attendance:"",marks:""});

  const fetch = async ()=>{
    const res = await axios.get(API+"/students");
    setStudents(res.data);
  };

  useEffect(()=>{fetch();},[]);

  const add = async ()=>{
    await axios.post(API+"/students",form);
    setForm({name:"",attendance:"",marks:""});
    fetch();
  };

  const del = async(id)=>{
    await axios.delete(API+"/students/"+id);
    fetch();
  };

  return (
    <div style={{textAlign:"center"}}>
      <h1>Student Management</h1>

      <input placeholder="Name" value={form.name} onChange={e=>setForm({...form,name:e.target.value})}/>
      <input placeholder="Attendance" value={form.attendance} onChange={e=>setForm({...form,attendance:e.target.value})}/>
      <input placeholder="Marks" value={form.marks} onChange={e=>setForm({...form,marks:e.target.value})}/>
      <button onClick={add}>Add</button>

      <table border="1" style={{margin:"20px auto"}}>
        <thead>
          <tr>
            <th>Name</th><th>Attendance</th><th>Marks</th><th>Action</th>
          </tr>
        </thead>
        <tbody>
          {students.map(s=>(
            <tr key={s._id}>
              <td>{s.name}</td>
              <td>{s.attendance}</td>
              <td>{s.marks}</td>
              <td><button onClick={()=>del(s._id)}>Delete</button></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;
